import React, { useEffect, useMemo, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  computeCurrentCounts,
  isVictory,
  makeBridgeKey,
} from './utils/hashiLogic';

const GRID = 40;
const WIDTH = 800;
const HEIGHT = 600;

const islandPixel = (isl) => ({ cx: isl.x * GRID, cy: isl.y * GRID });

const findIslandById = (islands, id) => islands.find((i) => i.id === id);

const findNextIslandInDirection = (islands, fromId, dir) => {
  const from = findIslandById(islands, fromId);
  if (!from) return fromId;

  let candidates = [];
  if (dir === 'left') {
    candidates = islands
      .filter((i) => i.y === from.y && i.x < from.x)
      .sort((a, b) => b.x - a.x);
  } else if (dir === 'right') {
    candidates = islands
      .filter((i) => i.y === from.y && i.x > from.x)
      .sort((a, b) => a.x - b.x);
  } else if (dir === 'up') {
    candidates = islands
      .filter((i) => i.x === from.x && i.y < from.y)
      .sort((a, b) => b.y - a.y);
  } else if (dir === 'down') {
    candidates = islands
      .filter((i) => i.x === from.x && i.y > from.y)
      .sort((a, b) => a.y - b.y);
  }

  return candidates[0]?.id ?? fromId;
};

export default function App() {
  const [puzzleName, setPuzzleName] = useState('Easy');

  const puzzle = useMemo(
    () => puzzles.find((p) => p.name === puzzleName) ?? puzzles[0],
    [puzzleName]
  );

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // first click island id
  const [cursorId, setCursorId] = useState(0);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);

  const counts = useMemo(() => computeCurrentCounts(puzzle.islands, bridges), [puzzle.islands, bridges]);

  // On puzzle change: fully reset everything in one sweep.
  useEffect(() => {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setVictory(false);
    setCursorId(0);
  }, [puzzleName]);

  // Global key handlers (not tied to focus)
  useEffect(() => {
    const onKeyDown = (e) => {
      if (e.key === 'Escape') {
        setSelectedId(null);
        setError(null);
        setCursorId(0);
        return;
      }

      if (e.key === 'ArrowLeft' || e.key === 'ArrowRight' || e.key === 'ArrowUp' || e.key === 'ArrowDown') {
        e.preventDefault();
        const dir =
          e.key === 'ArrowLeft'
            ? 'left'
            : e.key === 'ArrowRight'
              ? 'right'
              : e.key === 'ArrowUp'
                ? 'up'
                : 'down';
        setCursorId((prev) => findNextIslandInDirection(puzzle.islands, prev, dir));
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        const cur = findIslandById(puzzle.islands, cursorId);
        if (!cur) return;

        setBridges((prevBridges) => {
          // We may not update bridges on first Enter; still need selection/error/cursor behavior.
          if (selectedId === null) {
            setSelectedId(cur.id);
            setError(null);
            return prevBridges;
          }

          if (selectedId === cur.id) {
            // Treat Enter on same island as cancel selection.
            setSelectedId(null);
            setError(null);
            setCursorId(0);
            return prevBridges;
          }

          const from = findIslandById(puzzle.islands, selectedId);
          const to = cur;
          const key = makeBridgeKey(from, to);
          const current = prevBridges.get(key) ?? 0;
          const desired = current === 0 ? 1 : current === 1 ? 2 : 0;
          const delta = desired - current;

          // removal is always allowed if desired=0; adding validated.
          if (delta > 0) {
            const { valid, error: err } = canAddBridge(puzzle.islands, prevBridges, from, to, delta);
            if (!valid) {
              setError(err);
              setSelectedId(null); // important: reset pair on error
              setCursorId(0);
              return prevBridges;
            }
          }

          const next = new Map(prevBridges);
          if (desired === 0) next.delete(key);
          else next.set(key, desired);

          setSelectedId(null);
          setError(null);
          setCursorId(0);
          setVictory(isVictory(puzzle.islands, next));
          return next;
        });
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [puzzle.islands, cursorId, selectedId]);

  const cycleBridgeByClickPair = (from, to) => {
    setBridges((prev) => {
      const key = makeBridgeKey(from, to);
      const current = prev.get(key) ?? 0;
      const desired = current === 0 ? 1 : current === 1 ? 2 : 0;
      const delta = desired - current;

      if (delta > 0) {
        const { valid, error: err } = canAddBridge(puzzle.islands, prev, from, to, delta);
        if (!valid) {
          setError(err);
          setSelectedId(null); // reset pair on error
          setCursorId(0);
          return prev;
        }
      }

      const next = new Map(prev);
      if (desired === 0) next.delete(key);
      else next.set(key, desired);

      setSelectedId(null);
      setError(null);
      setCursorId(0);
      setVictory(isVictory(puzzle.islands, next));
      return next;
    });
  };

  const handleIslandClick = (isl) => {
    setCursorId(isl.id);
    if (selectedId === null) {
      setSelectedId(isl.id);
      setError(null);
      return;
    }

    if (selectedId === isl.id) {
      setSelectedId(null);
      setError(null);
      setCursorId(0);
      return;
    }

    const from = findIslandById(puzzle.islands, selectedId);
    const to = isl;
    cycleBridgeByClickPair(from, to);
  };

  const removeBridge = (from, to) => {
    setBridges((prev) => {
      const key = makeBridgeKey(from, to);
      if (!prev.has(key)) return prev;
      const next = new Map(prev);
      next.delete(key);
      setSelectedId(null);
      setError(null);
      setCursorId(0);
      setVictory(isVictory(puzzle.islands, next));
      return next;
    });
  };

  const onReset = () => {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setVictory(false);
    setCursorId(0);
  };

  const renderBridges = () => {
    const lines = [];
    for (const [k, n] of bridges.entries()) {
      if (!n) continue;
      const [x1, y1, x2, y2] = k.split(',').map(Number);
      const from = puzzle.islands.find((i) => i.x === x1 && i.y === y1);
      const to = puzzle.islands.find((i) => i.x === x2 && i.y === y2);
      if (!from || !to) continue;

      const p1 = { x: x1 * GRID, y: y1 * GRID };
      const p2 = { x: x2 * GRID, y: y2 * GRID };
      const isHoriz = y1 === y2;

      const mkHandlers = () => ({
        onContextMenu: (e) => {
          e.preventDefault();
          removeBridge(from, to);
        },
        onClick: (e) => {
          if (e.ctrlKey) {
            removeBridge(from, to);
          }
        },
      });

      const baseProps = {
        stroke: '#0f0',
        strokeWidth: 4,
        strokeLinecap: 'round',
        ...mkHandlers(),
      };

      if (n === 1) {
        lines.push(
          <line
            key={`b-${k}-1`}
            x1={p1.x}
            y1={p1.y}
            x2={p2.x}
            y2={p2.y}
            {...baseProps}
          />
        );
      } else if (n === 2) {
        const offset = 6;
        if (isHoriz) {
          lines.push(
            <line
              key={`b-${k}-a`}
              x1={p1.x}
              y1={p1.y - offset}
              x2={p2.x}
              y2={p2.y - offset}
              {...baseProps}
            />
          );
          lines.push(
            <line
              key={`b-${k}-b`}
              x1={p1.x}
              y1={p1.y + offset}
              x2={p2.x}
              y2={p2.y + offset}
              {...baseProps}
            />
          );
        } else {
          lines.push(
            <line
              key={`b-${k}-a`}
              x1={p1.x - offset}
              y1={p1.y}
              x2={p2.x - offset}
              y2={p2.y}
              {...baseProps}
            />
          );
          lines.push(
            <line
              key={`b-${k}-b`}
              x1={p1.x + offset}
              y1={p1.y}
              x2={p2.x + offset}
              y2={p2.y}
              {...baseProps}
            />
          );
        }
      }
    }
    return lines;
  };

  const cursorIsland = findIslandById(puzzle.islands, cursorId) ?? puzzle.islands[0];
  const cursorPx = cursorIsland ? islandPixel(cursorIsland) : { cx: 0, cy: 0 };

  return (
    <div style={{ position: 'relative', width: `${WIDTH}px`, height: `${HEIGHT}px` }}>
      <div style={{ position: 'absolute', left: 0, top: 0, padding: 8, zIndex: 2 }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleName}
            onChange={(e) => setPuzzleName(e.target.value)}
            style={{
              background: 'black',
              color: '#0f0',
              border: '1px solid #0f0',
              fontFamily: 'monospace',
            }}
          >
            <option>Easy</option>
            <option>Medium</option>
            <option>Hard</option>
          </select>
        </label>{' '}
        <button
          onClick={onReset}
          style={{
            marginLeft: 8,
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            cursor: 'pointer',
          }}
        >
          Reset
        </button>
        {error ? (
          <div className="error-message" style={{ marginTop: 8 }}>
            {error}
          </div>
        ) : null}
        {victory ? (
          <div className="victory-banner" style={{ marginTop: 8, fontWeight: 'bold' }}>
            SOLVED!
          </div>
        ) : null}
      </div>

      <svg width={WIDTH} height={HEIGHT} style={{ position: 'absolute', left: 0, top: 0 }}>
        {/* cursor (not a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorPx.cx - 18}
            y={cursorPx.cy - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth={2}
            strokeDasharray="4 4"
          />
        ) : null}

        {/* bridges */}
        {renderBridges()}

        {/* islands */}
        {puzzle.islands.map((isl) => {
          const { cx, cy } = islandPixel(isl);
          const isSelected = selectedId === isl.id;
          const current = counts.get(isl.id) ?? 0;
          return (
            <g key={isl.id}>
              <circle
                cx={cx}
                cy={cy}
                r={14}
                fill={isSelected ? '#0f0' : 'black'}
                stroke="#0f0"
                strokeWidth={2}
                onClick={() => handleIslandClick(isl)}
                style={{ cursor: 'pointer' }}
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={14}
                fill={isSelected ? 'black' : '#0f0'}
                onClick={() => handleIslandClick(isl)}
                style={{ cursor: 'pointer', userSelect: 'none' }}
              >
                {isl.value}
              </text>
              <text
                x={cx}
                y={cy + 28}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0f0"
                style={{ userSelect: 'none' }}
              >
                {current}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
