  const a1 = { x: from.x, y: from.y };
  const a2 = { x: to.x, y: to.y };

  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    if (keyToIgnore && k === keyToIgnore) continue;

    const [x1, y1, x2, y2] = k.split(',').map(Number);
    const b1 = { x: x1, y: y1 };
    const b2 = { x: x2, y: y2 };

    // skip if share endpoints
    const sharesEndpoint =
