  } else if (dir === 'right') {
    candidates = islands
      .filter((i) => i.y === from.y && i.x > from.x)
      .sort((a, b) => a.x - b.x);
  } else if (dir === 'up') {
    candidates = islands
      .filter((i) => i.x === from.x && i.y < from.y)
      .sort((a, b) => b.y - a.y);
  } else if (dir === 'down') {
    candidates = islands
      .filter((i) => i.x === from.x && i.y > from.y)
      .sort((a, b) => a.y - b.y);
  }

  return candidates[0]?.id ?? fromId;
};

export default function App() {
  const [puzzleName, setPuzzleName] = useState('Easy');

  const puzzle = useMemo(
    () => puzzles.find((p) => p.name === puzzleName) ?? puzzles[0],
    [puzzleName]
  );

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // first click island id
  const [cursorId, setCursorId] = useState(0);
