  const renderBridges = () => {
    const lines = [];
    for (const [k, n] of bridges.entries()) {
      if (!n) continue;
      const [x1, y1, x2, y2] = k.split(',').map(Number);
      const from = puzzle.islands.find((i) => i.x === x1 && i.y === y1);
      const to = puzzle.islands.find((i) => i.x === x2 && i.y === y2);
      if (!from || !to) continue;

      const p1 = { x: x1 * GRID, y: y1 * GRID };
      const p2 = { x: x2 * GRID, y: y2 * GRID };
      const isHoriz = y1 === y2;

      const mkHandlers = () => ({
        onContextMenu: (e) => {
          e.preventDefault();
          removeBridge(from, to);
        },
        onClick: (e) => {
          if (e.ctrlKey) {
            removeBridge(from, to);
          }
        },
      });

      const baseProps = {
        stroke: '#0f0',
        strokeWidth: 4,
        strokeLinecap: 'round',
        ...mkHandlers(),
      };

      if (n === 1) {
        lines.push(
          <line
            key={`b-${k}-1`}
            x1={p1.x}
            y1={p1.y}
            x2={p2.x}
            y2={p2.y}
            {...baseProps}
          />
        );
      } else if (n === 2) {
        const offset = 6;
        if (isHoriz) {
          lines.push(
            <line
              key={`b-${k}-a`}
              x1={p1.x}
              y1={p1.y - offset}
              x2={p2.x}
              y2={p2.y - offset}
              {...baseProps}
            />
          );
          lines.push(
            <line
              key={`b-${k}-b`}
              x1={p1.x}
              y1={p1.y + offset}
              x2={p2.x}
              y2={p2.y + offset}
              {...baseProps}
            />
          );
        } else {
          lines.push(
            <line
              key={`b-${k}-a`}
              x1={p1.x - offset}
              y1={p1.y}
              x2={p2.x - offset}
              y2={p2.y}
              {...baseProps}
            />
          );
          lines.push(
            <line
              key={`b-${k}-b`}
              x1={p1.x + offset}
              y1={p1.y}
              x2={p2.x + offset}
              y2={p2.y}
              {...baseProps}
            />
          );
        }
      }
    }
    return lines;
  };

  const cursorIsland = findIslandById(puzzle.islands, cursorId) ?? puzzle.islands[0];
  const cursorPx = cursorIsland ? islandPixel(cursorIsland) : { cx: 0, cy: 0 };

  return (
    <div style={{ position: 'relative', width: `${WIDTH}px`, height: `${HEIGHT}px` }}>
      <div style={{ position: 'absolute', left: 0, top: 0, padding: 8, zIndex: 2 }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleName}
            onChange={(e) => setPuzzleName(e.target.value)}
            style={{
              background: 'black',
              color: '#0f0',
              border: '1px solid #0f0',
              fontFamily: 'monospace',
            }}
          >
            <option>Easy</option>
            <option>Medium</option>
            <option>Hard</option>
          </select>
        </label>{' '}
        <button
          onClick={onReset}
          style={{
            marginLeft: 8,
            background: 'black',
            color: '#0f0',
            border: '1px solid #0f0',
            fontFamily: 'monospace',
            cursor: 'pointer',
          }}
        >
          Reset
        </button>
        {error ? (
          <div className="error-message" style={{ marginTop: 8 }}>
            {error}
          </div>
        ) : null}
        {victory ? (
          <div className="victory-banner" style={{ marginTop: 8, fontWeight: 'bold' }}>
            SOLVED!
          </div>
        ) : null}
      </div>

      <svg width={WIDTH} height={HEIGHT} style={{ position: 'absolute', left: 0, top: 0 }}>
        {/* cursor (not a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorPx.cx - 18}
            y={cursorPx.cy - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#0f0"
            strokeWidth={2}
            strokeDasharray="4 4"
          />
        ) : null}

        {/* bridges */}
        {renderBridges()}

        {/* islands */}
        {puzzle.islands.map((isl) => {
          const { cx, cy } = islandPixel(isl);
          const isSelected = selectedId === isl.id;
          const current = counts.get(isl.id) ?? 0;
          return (
            <g key={isl.id}>
              <circle
                cx={cx}
                cy={cy}
                r={14}
                fill={isSelected ? '#0f0' : 'black'}
                stroke="#0f0"
                strokeWidth={2}
                onClick={() => handleIslandClick(isl)}
                style={{ cursor: 'pointer' }}
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={14}
                fill={isSelected ? 'black' : '#0f0'}
                onClick={() => handleIslandClick(isl)}
                style={{ cursor: 'pointer', userSelect: 'none' }}
              >
                {isl.value}
              </text>
              <text
                x={cx}
                y={cy + 28}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0f0"
                style={{ userSelect: 'none' }}
              >
                {current}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
